noncompliant:
string userInput = GetUserInput();
string command = $"ping {userInput}"; // Noncompliant: user input directly in command
Process.Start("cmd", "/c " + command);

compliant:
string userInput = GetUserInput();
string safeInput = Regex.Replace(userInput, @"[^\w\.-]", "");
ProcessStartInfo psi = new ProcessStartInfo("ping", safeInput); // Compliant: separate command and arguments
Process.Start(psi);
